/// Remaining block devices not used for the root filesystem.
static EXTRA_BLOCK_DEVS: Mutex<Option<AxDeviceContainer<AxBlockDevice>>> =
    Mutex::new(None);

/// Take the remaining block devices (if any) after root filesystem initialization.
pub fn take_extra_block_devs() -> Option<AxDeviceContainer<AxBlockDevice>> {
    EXTRA_BLOCK_DEVS.lock().take()
}

/// Initializes the filesystem subsystem using the first available block device.
/// Any additional block devices are saved for later use (e.g. mounting a test disk).
pub fn init_filesystems(mut block_devs: AxDeviceContainer<AxBlockDevice>) {
    info!("Initialize filesystem subsystem...");

    let dev = block_devs.take_one().expect("No block device found!");
    info!("  use block device 0: {:?}", dev.device_name());

    let (fs, filesystem) = fs::new_default_with_fs(dev).expect("Failed to initialize filesystem");
    info!("  filesystem type: {:?}", fs.name());

    let mp = axfs_ng_vfs::Mountpoint::new_root(&filesystem);
    ROOT_FS_CONTEXT.call_once(|| FsContext::new_with_fs(mp.root_location(), fs));

    if !block_devs.is_empty() {
        info!("  saving {} extra block device(s)", block_devs.len());
        *EXTRA_BLOCK_DEVS.lock() = Some(block_devs);
    }
}

